func:
// node-red-node-sqlite는 단일 PRAGMA만 실행 가능
// 순차 체인으로 5개 PRAGMA 실행
var pragmas = [
  'PRAGMA journal_mode = WAL',
  'PRAGMA busy_timeout = 5000',
  'PRAGMA synchronous = NORMAL',
  'PRAGMA cache_size = -8000',
  'PRAGMA temp_store = MEMORY'
];
msg._pragmaList = pragmas;
msg._pragmaIdx = 0;
msg.topic = pragmas[0];
node.warn('⚙️ SQLite PRAGMA 설정 시작 (5개)');
return msg;

var idx = (msg._pragmaIdx || 0) + 1;
var list = msg._pragmaList || [];
if (idx < list.length) {
  msg._pragmaIdx = idx;
  msg.topic = list[idx];
  return [msg, null];
}
node.warn('✅ PRAGMA 5개 설정 완료');
return [null, msg];

msg.topic = `
CREATE TABLE IF NOT EXISTS sensor_data (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  timestamp TEXT NOT NULL,
  farm_id TEXT NOT NULL,
  house_id TEXT NOT NULL,
  sensor_id TEXT NOT NULL,
  value REAL,
  synced INTEGER DEFAULT 0
);
`;
return msg;

msg.topic = `
CREATE INDEX IF NOT EXISTS idx_sensor_timestamp ON sensor_data(timestamp);
CREATE INDEX IF NOT EXISTS idx_sensor_synced ON sensor_data(synced);
CREATE INDEX IF NOT EXISTS idx_sensor_farm_house ON sensor_data(farm_id, house_id);
CREATE INDEX IF NOT EXISTS idx_sensor_synced_ts ON sensor_data(synced, timestamp);
CREATE INDEX IF NOT EXISTS idx_sensor_synced_farm_house ON sensor_data(synced, farm_id, house_id, timestamp);
`;
return msg;

msg.topic = `
CREATE TABLE IF NOT EXISTS config_cache (
  id INTEGER PRIMARY KEY,
  farm_id TEXT NOT NULL,
  house_id TEXT NOT NULL,
  config_json TEXT NOT NULL,
  version INTEGER DEFAULT 0,
  updated_at TEXT NOT NULL
);
`;
return msg;

msg.topic = `
CREATE TABLE IF NOT EXISTS control_logs (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  timestamp TEXT NOT NULL,
  device_id TEXT NOT NULL,
  command TEXT NOT NULL,
  source TEXT NOT NULL,
  synced INTEGER DEFAULT 0
);
`;
return msg;

node.warn('✅ SmartFarm SQLite DB 초기화 완료');
node.status({ fill: 'green', shape: 'dot', text: '초기화 완료' });
msg.payload = 'SQLite DB 초기화 완료: sensor_data, config_cache, automation_rules, control_logs';
return msg;

var serverUrl = env.get('SERVER_URL') || 'http://192.168.137.1:3000';
var farmId = env.get('FARM_ID') || 'farm_001';
msg.url = serverUrl + '/api/config/system-settings/' + farmId;
node.status({fill:'yellow',shape:'ring',text:'설정 조회 중...'});
return msg;

var retentionDays = 60;
try {
    if (msg.payload && msg.payload.success && msg.payload.data) {
        retentionDays = msg.payload.data.retentionDays || 60;
        global.set('retentionDays', retentionDays);
        node.warn('서버 설정 반영: ' + retentionDays + '일 보관');
    } else {
        retentionDays = global.get('retentionDays') || 60;
        node.warn('캐시 설정 사용: ' + retentionDays + '일 보관');
    }
} catch(e) {
    retentionDays = global.get('retentionDays') || 60;
    node.warn('기본 설정 사용: ' + retentionDays + '일 보관');
}
msg.retentionDays = retentionDays;
msg.topic = "DELETE FROM sensor_data WHERE synced = 1 AND timestamp < datetime('now', '-" + retentionDays + " days')";
node.status({fill:'blue',shape:'dot',text:retentionDays+'일 보관'});
return msg;

var changes = msg.payload ? msg.payload.changes || 0 : 0;
var days = msg.retentionDays || 60;
node.warn('🗑️ ' + days + '일 이상 데이터 ' + changes + '건 삭제');
node.status({ fill: 'blue', shape: 'dot', text: changes + '건 삭제 (' + days + '일 보관)' });
return msg;
